trigger.body:
    vStatus VARCHAR2(300);
BEGIN
    IF (DELETING) THEN
        SELECT qd.state INTO vStatus FROM ssdqsi_quota_detail_line as qdl
        inner join ssdqsi_quota_detail qd on  qdl.ssdqsi_quota_detail_id=qd.ssdqsi_quota_detail_id  
        WHERE ssdqsi_quota_detail_line_id=:OLD.ssdqsi_quota_detail_line_id;
        IF (vStatus = 'SSDQSI_PR') THEN
            RAISE_APPLICATION_ERROR(-20000, '@ssdqsi_error_process_line@') ;
        END IF;
    END IF;
    RETURN OLD;
    END SSDQSI_PENDING_INCOME_STATUS
